SELECT DISTINCT u.user_name
FROM users u
JOIN program_applications pa ON u.user_id = pa.user_id;

SELECT COUNT(DISTINCT user_id) AS number_of_applicants
FROM program_applications
WHERE STRFTIME('%Y', application_date) = '2023';

SELECT application_id
FROM program_applications
WHERE status IN ('pending', 'accepted');

SELECT DISTINCT institutes.institute_name
FROM institutes
WHERE institutes.city_name LIKE '%New York%';
